module loadable_counter(
    input clk,
    input reset,
    input load,
    input [3:0] load_value,
    output reg [3:0] count
    );
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 4'b0;
        else if (load)
            count <= load_value;
        else
            count <= count + 1;
    end
endmodule
